productCreate.query:
#graphql
  mutation MarketLocalizationProductCreate($product: ProductCreateInput!) {
    productCreate(product: $product) {
      product {
        id
        handle
        title
        status
        metafields(first: 5, namespace: "custom") {
          nodes {
            id
            namespace
            key
            type
            value
            compareDigest
            createdAt
            updatedAt
            ownerType
          }
        }
      }
      userErrors {
        field
        message
      }
    }
  }

