moneyDefinitionCreate.query:
#graphql
  mutation MarketLocalizationMetafieldDefinitionCreate($definition: MetafieldDefinitionInput!) {
    metafieldDefinitionCreate(definition: $definition) {
      createdDefinition {
        id
        namespace
        key
        ownerType
        type {
          name
        }
      }
      userErrors {
        field
        message
        code
      }
    }
  }

moneyMetafieldsSet.query:
#graphql
  mutation MarketLocalizationMetafieldsSet($metafields: [MetafieldsSetInput!]!) {
    metafieldsSet(metafields: $metafields) {
      metafields {
        id
        namespace
        key
        type
        value
        compareDigest
        createdAt
        updatedAt
        ownerType
        owner {
          ... on Product {
            id
          }
        }
      }
      userErrors {
        field
        message
        code
        elementIndex
      }
    }
  }

